SELECT *
FROM models
WHERE model_id NOT IN (
    SELECT model_id
    FROM experiments
);

SELECT processing_software, processing_date 
FROM data_provenance 
WHERE variable_id BETWEEN 1 AND 5;

SELECT AVG(julianday(D.access_date) - julianday(P.processing_date)) AS average_time_difference
FROM data_access D
JOIN data_provenance P ON D.variable_id = P.variable_id;

SELECT processing_steps
FROM data_provenance
WHERE source_data_id = 'data123';

SELECT m.model_id, m.model_name, COUNT(e.experiment_id) AS num_experiments_used
FROM models m
LEFT JOIN experiments e ON m.model_id = e.model_id
JOIN users u ON e.experiment_id IN (
    SELECT experiment_id FROM experiments WHERE experiment_contact_person = 'jdoe'
)
WHERE m.model_id IN (
    SELECT model_id FROM experiments WHERE experiment_contact_person = 'jdoe'
)
GROUP BY m.model_id, m.model_name;
